// Test: Write empty index
TEST(index_io_write_empty) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, INDEX_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // First backup the original index
    GitIndexFull original = {};
    if (!git_index_open_full(&repo, &original)) {
        git_repo_close(&repo);
        TEST_SKIP("Could not open original index");
    }

    // Create empty index
    GitIndexFull empty = {};
    empty.version = 2;
    empty.entries = new GitIndexEntryFull[1];
    empty.entry_count = 0;
    empty.capacity = 1;

    // Lock and write
    if (!git_index_lock(&repo, 1000)) {
        git_index_close_full(&original);
        delete[] empty.entries;
        git_repo_close(&repo);
        TEST_SKIP("Could not acquire index lock");
    }

    bool write_result = git_index_write(&repo, &empty);
    git_index_unlock(&repo);

    // Verify write succeeded
    TEST_ASSERT_TRUE(write_result);

    // Read back and verify empty
    GitIndexFull readback = {};
    bool read_result = git_index_open_full(&repo, &readback);
    TEST_ASSERT_TRUE(read_result);
    TEST_ASSERT_EQ(readback.entry_count, (size_t)0);
    git_index_close_full(&readback);

    // Restore original index
    git_index_lock(&repo, 1000);
    git_index_write(&repo, &original);
    git_index_unlock(&repo);

    git_index_close_full(&original);
    delete[] empty.entries;
    git_repo_close(&repo);
}

