// Test: Write multiple entries and verify sorted output
TEST(index_io_write_multiple_entries_sorted) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, INDEX_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup original
    GitIndexFull original = {};
    if (!git_index_open_full(&repo, &original)) {
        git_repo_close(&repo);
        TEST_SKIP("Could not open original index");
    }

    // Create index with entries in WRONG order (git_index_write should sort)
    GitIndexFull unsorted = {};
    unsorted.version = 2;
    unsorted.entries = new GitIndexEntryFull[3];
    unsorted.entry_count = 3;
    unsorted.capacity = 3;

    memset(unsorted.entries, 0, sizeof(GitIndexEntryFull) * 3);

    // Add in reverse alphabetical order
    unsorted.entries[0].mode = Git::MODE_FILE;
    strcpy_s(unsorted.entries[0].sha, FIXTURE_FILE1_SHA);
    strcpy_s(unsorted.entries[0].path, "zzz.txt");

    unsorted.entries[1].mode = Git::MODE_FILE;
    strcpy_s(unsorted.entries[1].sha, FIXTURE_FILE2_SHA);
    strcpy_s(unsorted.entries[1].path, "mmm.txt");

    unsorted.entries[2].mode = Git::MODE_FILE;
    strcpy_s(unsorted.entries[2].sha, FIXTURE_FEATURE_SHA);
    strcpy_s(unsorted.entries[2].path, "aaa.txt");

    // Write
    if (!git_index_lock(&repo, 1000)) {
        git_index_close_full(&original);
        delete[] unsorted.entries;
        git_repo_close(&repo);
        TEST_SKIP("Could not acquire index lock");
    }

    bool write_result = git_index_write(&repo, &unsorted);
    git_index_unlock(&repo);
    TEST_ASSERT_TRUE(write_result);

    // Read back and verify sorted
    GitIndexFull readback = {};
    TEST_ASSERT_TRUE(git_index_open_full(&repo, &readback));
    TEST_ASSERT_EQ(readback.entry_count, (size_t)3);

    // Should be sorted: aaa.txt, mmm.txt, zzz.txt
    TEST_ASSERT_STREQ(readback.entries[0].path, "aaa.txt");
    TEST_ASSERT_STREQ(readback.entries[1].path, "mmm.txt");
    TEST_ASSERT_STREQ(readback.entries[2].path, "zzz.txt");

    git_index_close_full(&readback);

    // Restore original
    git_index_lock(&repo, 1000);
    git_index_write(&repo, &original);
    git_index_unlock(&repo);

    git_index_close_full(&original);
    delete[] unsorted.entries;
    git_repo_close(&repo);
}

// Test: Roundtrip - read, write, read produces identical result
TEST(index_io_write_roundtrip) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, INDEX_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Read original
    GitIndexFull original = {};
    if (!git_index_open_full(&repo, &original)) {
        git_repo_close(&repo);
        TEST_SKIP("Could not open original index");
    }

    // Write it back
    if (!git_index_lock(&repo, 1000)) {
        git_index_close_full(&original);
        git_repo_close(&repo);
        TEST_SKIP("Could not acquire index lock");
    }

    bool write_result = git_index_write(&repo, &original);
    git_index_unlock(&repo);
    TEST_ASSERT_TRUE(write_result);

    // Read again
    GitIndexFull readback = {};
    TEST_ASSERT_TRUE(git_index_open_full(&repo, &readback));

    // Verify same entry count
    TEST_ASSERT_EQ(readback.entry_count, original.entry_count);

    // Verify each entry matches
    for (size_t i = 0; i < original.entry_count; i++) {
        TEST_ASSERT_STREQ(readback.entries[i].path, original.entries[i].path);
        TEST_ASSERT_STREQ(readback.entries[i].sha, original.entries[i].sha);
        TEST_ASSERT_EQ(readback.entries[i].mode, original.entries[i].mode);
    }

    git_index_close_full(&readback);
    git_index_close_full(&original);
    git_repo_close(&repo);
}

