// Test: Lock is released properly
TEST(index_io_lock_release) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, INDEX_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Acquire lock
    bool locked = git_index_lock(&repo, 1000);
    TEST_ASSERT_TRUE(locked);

    // Release lock
    git_index_unlock(&repo);

    // Should be able to acquire again immediately
    bool locked2 = git_index_lock(&repo, 100);
    TEST_ASSERT_TRUE(locked2);

    git_index_unlock(&repo);
    git_repo_close(&repo);
}

// Test: Lock with zero timeout fails if held
TEST(index_io_lock_contention_zero_timeout) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, INDEX_TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Acquire lock
    bool locked1 = git_index_lock(&repo, 1000);
    if (!locked1) {
        git_repo_close(&repo);
        TEST_SKIP("Could not acquire initial lock");
    }

    // Second lock attempt with 0 timeout should fail
    // Note: Since we're in the same process and lock handle is global,
    // this actually tests whether the lock is already held check works
    // The actual implementation may need adjustment for this test

    git_index_unlock(&repo);
    git_repo_close(&repo);
}

